+  }
+
+  const quantities = new Map();
+  for (const item of cart.items) {
+    quantities.set(item.sku, (quantities.get(item.sku) || 0) + item.qty);
+  }
+
+  for (const [sku, qty] of quantities) {
+    const available = catalog.products[sku].stock;
+    if (qty > available) {
+      cartError({ error: 'invalid_stock', sku, available, requested: qty });
+    }
+  }
+
+  const promotions = new Map();
+  for (const promotion of catalog.line_promotions) {
+    promotions.set(promotion.sku, promotion);
