+    ? Math.round(postLineDiscountCents * coupon.percent / 100)
+    : 0;
+  const taxCents = Math.round(taxablePostLineDiscountCents * catalog.tax_rates[cart.state]);
+  const shippingCents = postLineDiscountCents - couponDiscountCents >= catalog.free_shipping_min_cents
+    ? 0
+    : catalog.shipping_cents;
+
+  return {
+    subtotal_cents: subtotalCents,
+    line_discount_cents: lineDiscountCents,
+    coupon_discount_cents: couponDiscountCents,
