#!/usr/bin/env node
// harbor-tools — small command-line utilities for local workflows.
// Keep the core commands minimal and easy to understand.

const fs = require('fs');
const path = require('path');

const USAGE = `Usage: bench-cli <command> [options]

Commands:
  hello [--name NAME]        Print a greeting (default name: "world")
  version                    Print the CLI version from package.json
  cart --input PATH          Price a cart JSON file
  --help, -h                 Show this help

Examples:
  bench-cli hello
  bench-cli hello --name alice
  bench-cli version
  bench-cli cart --input cart.json
`;

function readPackageVersion() {
  const pkgPath = path.join(__dirname, '..', 'package.json');
  const raw = fs.readFileSync(pkgPath, 'utf8');
  return JSON.parse(raw).version;
}

function parseNameFlag(argv) {
  const idx = argv.indexOf('--name');
  if (idx === -1) return 'world';
  const value = argv[idx + 1];
  if (!value || value.startsWith('-')) {
    console.error('--name requires a value');
    process.exit(1);
  }
  return value;
}

function parseInputFlag(argv) {
  const idx = argv.indexOf('--input');
  if (idx === -1) {
    console.error('--input requires a value');
    process.exit(1);
  }
  const value = argv[idx + 1];
  if (!value || value.startsWith('-')) {
    console.error('--input requires a value');
    process.exit(1);
  }
  return value;
}

function cartError(error) {
  process.stderr.write(`${JSON.stringify(error)}\n`);
  process.exit(2);
}

function readCart(inputPath) {
  try {
    return JSON.parse(fs.readFileSync(inputPath, 'utf8'));
  } catch (error) {
    cartError({ error: 'invalid_json' });
  }
}

function readCatalog() {
  const catalogPath = path.join(__dirname, '..', 'data', 'catalog.json');
  return JSON.parse(fs.readFileSync(catalogPath, 'utf8'));
}

function hasOwn(object, key) {
  return Object.prototype.hasOwnProperty.call(object, key);
}

function priceCart(cart, catalog) {
  if (!cart || !Array.isArray(cart.items)) {
    cartError({ error: 'missing_items' });
  }

  for (const item of cart.items) {
    if (!hasOwn(catalog.products, item?.sku)) {
      cartError({ error: 'unknown_sku', sku: item?.sku });
    }
  }

  for (const item of cart.items) {
    if (typeof item?.qty !== 'number' || !Number.isInteger(item.qty) || item.qty <= 0) {
      cartError({ error: 'invalid_qty', sku: item?.sku });
    }
  }

  if (cart.coupon !== null && !hasOwn(catalog.coupons, cart.coupon)) {
    cartError({ error: 'unknown_coupon', coupon: cart.coupon });
  }

  if (!hasOwn(catalog.tax_rates, cart.state)) {
    cartError({ error: 'unknown_state', state: cart.state });
  }

  const quantities = new Map();
  for (const item of cart.items) {
    quantities.set(item.sku, (quantities.get(item.sku) || 0) + item.qty);
  }

  for (const [sku, qty] of quantities) {
    const available = catalog.products[sku].stock;
    if (qty > available) {
      cartError({ error: 'invalid_stock', sku, available, requested: qty });
    }
  }

  const promotions = new Map();
  for (const promotion of catalog.line_promotions) {
    promotions.set(promotion.sku, promotion);
  }

  let subtotalCents = 0;
  let lineDiscountCents = 0;
  let taxablePostLineDiscountCents = 0;
  const items = [];

  for (const [sku, qty] of quantities) {
    const product = catalog.products[sku];
    const lineSubtotalCents = qty * product.unit_cents;
    const promotion = promotions.get(sku);
    let lineDiscount = 0;

    if (promotion?.type === 'buy_x_get_y_free') {
      lineDiscount = Math.floor(qty / (promotion.buy_qty + promotion.free_qty))
        * promotion.free_qty * product.unit_cents;
    } else if (promotion?.type === 'per_unit_discount_cents' && qty >= promotion.min_qty) {
      lineDiscount = promotion.per_unit_discount_cents * qty;
    }

    const lineTotalCents = lineSubtotalCents - lineDiscount;
    subtotalCents += lineSubtotalCents;
    lineDiscountCents += lineDiscount;
    if (catalog.taxable_codes[product.tax_code] === true) {
      taxablePostLineDiscountCents += lineTotalCents;
    }
    items.push({
      sku,
      qty,
      line_subtotal_cents: lineSubtotalCents,
      line_discount_cents: lineDiscount,
      line_total_cents: lineTotalCents,
    });
  }

  const coupon = cart.coupon === null ? null : catalog.coupons[cart.coupon];
  const postLineDiscountCents = subtotalCents - lineDiscountCents;
  const couponDiscountCents = coupon && postLineDiscountCents >= coupon.min_subtotal_cents
    ? Math.round(postLineDiscountCents * coupon.percent / 100)
    : 0;
  const taxCents = Math.round(taxablePostLineDiscountCents * catalog.tax_rates[cart.state]);
  const shippingCents = postLineDiscountCents - couponDiscountCents >= catalog.free_shipping_min_cents
    ? 0
    : catalog.shipping_cents;

  return {
    subtotal_cents: subtotalCents,
    line_discount_cents: lineDiscountCents,
    coupon_discount_cents: couponDiscountCents,
    tax_cents: taxCents,
    shipping_cents: shippingCents,
    total_cents: postLineDiscountCents - couponDiscountCents + taxCents + shippingCents,
    items,
  };
}

function main(argv) {
  const [command, ...rest] = argv;

  if (!command || command === '--help' || command === '-h') {
    process.stdout.write(USAGE);
    return;
  }

  switch (command) {
    case 'hello': {
      const name = parseNameFlag(rest);
      console.log(`Hello, ${name}!`);
      return;
    }
    case 'version': {
      console.log(readPackageVersion());
      return;
    }
    case 'cart': {
      const inputPath = parseInputFlag(rest);
      const cart = readCart(inputPath);
      const catalog = readCatalog();
      console.log(JSON.stringify(priceCart(cart, catalog)));
      return;
    }
    default:
      console.error(`Unknown command: ${command}`);
      process.stderr.write(USAGE);
      process.exit(1);
  }
}

main(process.argv.slice(2));

