const { test } = require('node:test');
const assert = require('node:assert');
const { execFileSync, spawnSync } = require('node:child_process');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');

const CLI = path.join(__dirname, '..', 'bin', 'cli.js');

function run(args) {
  return execFileSync('node', [CLI, ...args], { encoding: 'utf8' });
}

function withCartFile(cart, callback) {
  const directory = fs.mkdtempSync(path.join(os.tmpdir(), 'bench-cli-'));
  const inputPath = path.join(directory, 'cart.json');
  fs.writeFileSync(inputPath, JSON.stringify(cart));

  try {
    return callback(inputPath);
  } finally {
    fs.rmSync(directory, { recursive: true, force: true });
  }
}

test('hello default', () => {
  const out = run(['hello']);
  assert.match(out, /Hello, world!/);
});

test('hello with --name', () => {
  const out = run(['hello', '--name', 'alice']);
  assert.match(out, /Hello, alice!/);
});

test('version prints package version', () => {
  const out = run(['version']);
  assert.match(out, /\d+\.\d+\.\d+/);
});

test('cart combines duplicate items and applies pricing rules', () => {
  const output = withCartFile({
    state: 'CA',
    coupon: 'ORDER10',
    items: [
      { sku: 'TEE', qty: 1 },
      { sku: 'BAG', qty: 2 },
      { sku: 'TEE', qty: 2 },
    ],
  }, (inputPath) => run(['cart', '--input', inputPath]));

  assert.deepStrictEqual(JSON.parse(output), {
    subtotal_cents: 13900,
    line_discount_cents: 3500,
    coupon_discount_cents: 1040,
    tax_cents: 858,
    shipping_cents: 0,
    total_cents: 10218,
    items: [
      {
        sku: 'TEE',
        qty: 3,
        line_subtotal_cents: 7500,
        line_discount_cents: 2500,
        line_total_cents: 5000,
      },
      {
        sku: 'BAG',
        qty: 2,
        line_subtotal_cents: 6400,
        line_discount_cents: 1000,
        line_total_cents: 5400,
      },
    ],
  });
});

test('cart reports combined quantities over stock as a JSON error', () => {
  const result = withCartFile({
    state: 'CA',
    coupon: null,
    items: [
      { sku: 'TEE', qty: 7 },
      { sku: 'TEE', qty: 5 },
    ],
  }, (inputPath) => spawnSync('node', [CLI, 'cart', '--input', inputPath], {
    encoding: 'utf8',
  }));

  assert.strictEqual(result.status, 2);
  assert.strictEqual(result.stdout, '');
  assert.deepStrictEqual(JSON.parse(result.stderr), {
    error: 'invalid_stock',
    sku: 'TEE',
    available: 10,
    requested: 12,
  });
});

